#include <bits/stdc++.h>
using namespace std;
const int maxn=1e5*55+5;
int son[maxn][55];
int fen[maxn];
int idx=0;
int xss=0;
int get_id(char c) {
	if(c>='a'&&c<='z') {
		return c-'a';
	} else {
		return c-'A'+26;
	}
}
void insert(string &s,int val) {
	int p=0;
	for(char c:s) {
		int u=get_id(c);
		if(!son[p][u]) {
			son[p][u]=++idx;
		}
		p=son[p][u];
	}
	if(fen[p]==0) {
		xss++;
	}
	fen[p]=val;
	cout<<"OK\n";
}
int query(string &s) {
	int p=0;
	for(char c:s) {
		int u=get_id(c);
		if(!son[p][u]) {
		return 0;}
		p=son[p][u];
	}
	return fen[p];
}
void sc(string &s) {
	int p=0;
	for(char c:s) {
		int u=get_id(c);
		if(!son[p][u]) {
			cout<<"Not found\n";
			return;
		}
		p=son[p][u];
	}
	if(fen[p]==0) {
		cout<<"Not found\n";
	} else {
		fen[p]=0;
		xss--;
		cout<<"Deleted successfully\n";
	}
}
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	int q;
	cin>>q;
	while(q--) {
		int op;
		cin>>op;
		if(op==1) {
			string s;
			int c;
			cin>>s>>c;
			insert(s,c);
		} else if(op==2) {
			string s;
			cin>>s;
			int res=query(s);
			if(res==0) {
				cout<<"Not found\n";
			} else {
				cout<<res<<"\n";
			}
		} else if(op==3) {
			string s;
			cin>>s;
			sc(s);
		} else if(op==4) {
			cout<<xss<<"\n";
		}
	}
	return 0;
}
